// Helper: extract slug from "creator/slug" or "slug" format
function getSlugFromEntry(entry) {
  if (typeof entry === 'string') return entry;
  var slug = entry[0];
  var lastSlash = slug.lastIndexOf('/');
  return lastSlash > 0 ? slug.substring(lastSlash + 1) : slug;
}

// Deprecated skills — API gone or skill no longer functional
// Format: slug maps to reason
const DEPRECATED = new Map([
  ['shop-product-search', 'api_gone: Shop.app API gone']
]);

// Helper: determine skill status
// "compatible_installed" — pre-installed frontend (5 skills)
// "compatible" — backend-available, whistant-compatible, not pre-installed (51 skills)
// "not_compatible" — deep screened, requires Python/shell/binaries, can't work (46 skills)
// "may_work_directly" — JS-only code found, simple screened, need testing (650+ skills)
// "may_not_work_directly" — not indexed, has non-JS code, can't use (40k+ skills - not in catalog)
function getSkillStatus(entry) {
  var slug = getSlugFromEntry(entry);
  if (COMPATIBLE_INSTALLED.has(slug)) return 'compatible_installed';
  if (COMPATIBLE.has(slug)) return 'compatible';
  if (NOT_COMPATIBLE.has(slug)) return 'not_compatible';
  if (DEPRECATED.has(slug)) return 'deprecated';
  return 'may_work_directly'; // JS-only found in catalog
}

